import { useState, useEffect, useRef } from "react";

const PHOTO_B64 = "";

const FONTS = `
  @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,500;0,600;1,300;1,400&family=Karla:wght@300;400;500;600&display=swap');
`;

const STYLES = `
  :root {
    --navy: #0B1927;
    --navy-mid: #142236;
    --navy-light: #1E3352;
    --gold: #C4973B;
    --gold-light: #DDB96A;
    --gold-pale: rgba(196,151,59,0.12);
    --cream: #F2EDE3;
    --warm-white: #FDFAF5;
    --muted: #7A9AB5;
    --muted-light: #A8C0D0;
    --border: rgba(196,151,59,0.25);
    --human: #3A7CA5;
    --human-light: rgba(58,124,165,0.15);
    --auto: #2A6B52;
    --auto-light: rgba(42,107,82,0.15);
  }

  * { margin: 0; padding: 0; box-sizing: border-box; }
  body { font-family: Karla, sans-serif; background: var(--navy); color: var(--cream); -webkit-font-smoothing: antialiased; }
  h1, h2, h3 { font-family: "Cormorant Garamond", serif; }

  /* NAV */
  .nav { position: fixed; top: 0; left: 0; right: 0; z-index: 100; display: flex; align-items: center; justify-content: space-between; padding: 20px 60px; transition: background 0.4s, backdrop-filter 0.4s; }
  .nav.scrolled { background: rgba(11,25,39,0.96); backdrop-filter: blur(12px); border-bottom: 1px solid var(--border); }
  .nav-logo { font-family: "Cormorant Garamond", serif; font-size: 22px; font-weight: 500; color: var(--cream); letter-spacing: 0.04em; }
  .nav-logo span { color: var(--gold); }
  .nav-links { display: flex; gap: 36px; list-style: none; font-size: 13px; letter-spacing: 0.1em; text-transform: uppercase; font-weight: 500; }
  .nav-links a { color: var(--muted-light); text-decoration: none; transition: color 0.2s; }
  .nav-links a:hover { color: var(--gold); }
  .nav-cta { background: transparent; border: 1px solid var(--gold); color: var(--gold); padding: 10px 24px; font-family: Karla, sans-serif; font-size: 13px; letter-spacing: 0.1em; text-transform: uppercase; cursor: pointer; transition: all 0.25s; }
  .nav-cta:hover { background: var(--gold); color: var(--navy); }

  /* HERO */
  .hero { min-height: 100vh; display: grid; grid-template-columns: 1fr 1fr; gap: 0; position: relative; overflow: hidden; }
  .hero-bg { position: absolute; inset: 0; background: radial-gradient(ellipse 80% 70% at 20% 60%, rgba(196,151,59,0.07) 0%, transparent 70%), radial-gradient(ellipse 60% 80% at 90% 20%, rgba(30,51,82,0.6) 0%, transparent 60%); }
  .hero-grid { position: absolute; inset: 0; opacity: 0.025; background-image: linear-gradient(var(--gold) 1px, transparent 1px), linear-gradient(90deg, var(--gold) 1px, transparent 1px); background-size: 60px 60px; }
  .hero-left { position: relative; display: flex; flex-direction: column; justify-content: center; padding: 140px 60px 80px 60px; z-index: 1; }
  .hero-right { position: relative; overflow: hidden; padding-top: 72px; }
  .hero-photo { width: 100%; height: 100%; object-fit: cover; object-position: 50% 12%; filter: grayscale(15%) contrast(1.05); }
  .hero-photo-overlay { position: absolute; inset: 0; background: linear-gradient(to right, rgba(11,25,39,0.5) 0%, transparent 45%), linear-gradient(to top, rgba(11,25,39,0.65) 0%, transparent 35%); }
  .hero-photo-tag { position: absolute; bottom: 40px; left: 40px; background: var(--gold); color: var(--navy); padding: 10px 20px; font-size: 11px; letter-spacing: 0.15em; text-transform: uppercase; font-weight: 700; }
  .hero-eyebrow { display: inline-flex; align-items: center; gap: 12px; font-size: 11px; letter-spacing: 0.2em; text-transform: uppercase; color: var(--gold); margin-bottom: 32px; font-weight: 600; }
  .hero-eyebrow::before { content: ""; display: block; width: 32px; height: 1px; background: var(--gold); }
  .hero-headline { font-size: clamp(42px, 4.5vw, 72px); font-weight: 300; line-height: 1.05; color: var(--warm-white); margin-bottom: 28px; letter-spacing: -0.01em; }
  .hero-headline em { font-style: italic; color: var(--gold-light); }
  .hero-sub { font-size: 17px; line-height: 1.75; color: var(--muted-light); max-width: 520px; margin-bottom: 48px; font-weight: 300; }
  .hero-ctas { display: flex; gap: 16px; align-items: center; flex-wrap: wrap; }
  .btn-primary { background: var(--gold); color: var(--navy); padding: 16px 36px; border: none; cursor: pointer; font-family: Karla, sans-serif; font-size: 13px; letter-spacing: 0.1em; text-transform: uppercase; font-weight: 600; transition: all 0.25s; }
  .btn-primary:hover { background: var(--gold-light); transform: translateY(-1px); }
  .btn-ghost { background: transparent; color: var(--cream); padding: 15px 36px; border: 1px solid rgba(242,237,227,0.3); cursor: pointer; font-family: Karla, sans-serif; font-size: 13px; letter-spacing: 0.1em; text-transform: uppercase; transition: all 0.25s; }
  .btn-ghost:hover { border-color: var(--cream); }
  .hero-stats { display: flex; gap: 40px; margin-top: 64px; padding-top: 36px; border-top: 1px solid var(--border); }
  .stat-number { font-family: "Cormorant Garamond", serif; font-size: 40px; font-weight: 300; color: var(--gold-light); line-height: 1; }
  .stat-label { font-size: 11px; letter-spacing: 0.1em; text-transform: uppercase; color: var(--muted); margin-top: 6px; }

  /* SECTION COMMON */
  section { padding: 100px 60px; }
  .section-eyebrow { font-size: 11px; letter-spacing: 0.2em; text-transform: uppercase; color: var(--gold); margin-bottom: 20px; font-weight: 600; display: flex; align-items: center; gap: 12px; }
  .section-eyebrow::before { content: ""; width: 24px; height: 1px; background: var(--gold); display: block; }
  .section-title { font-size: clamp(34px, 3.5vw, 54px); font-weight: 300; line-height: 1.1; color: var(--warm-white); margin-bottom: 20px; }
  .section-title em { font-style: italic; color: var(--gold-light); }
  .section-sub { font-size: 17px; line-height: 1.7; color: var(--muted-light); max-width: 580px; font-weight: 300; }
  .section-header { margin-bottom: 64px; }

  /* PHILOSOPHY STRIP */
  .philosophy { background: var(--gold); padding: 48px 60px; }
  .philosophy-inner { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 1px; background: rgba(11,25,39,0.15); }
  .philosophy-item { background: var(--gold); padding: 36px 40px; }
  .philosophy-label { font-size: 10px; letter-spacing: 0.25em; text-transform: uppercase; color: var(--navy); font-weight: 700; margin-bottom: 12px; opacity: 0.7; }
  .philosophy-text { font-family: "Cormorant Garamond", serif; font-size: 22px; font-weight: 400; color: var(--navy); line-height: 1.3; }


  /* VALUE PROP */
  .valueprop { background: var(--navy); }
  .vp-prose { max-width: 800px; margin: 0 auto 80px; text-align: center; }
  .vp-prose-text { font-family: "Cormorant Garamond", serif; font-size: clamp(20px, 2.2vw, 28px); font-weight: 300; line-height: 1.65; color: var(--cream); }
  .vp-prose-text em { font-style: italic; color: var(--gold-light); }
  .outcomes-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 2px; background: var(--border); }
  .outcome-card { background: var(--navy); padding: 52px 44px; position: relative; overflow: hidden; transition: background 0.3s; }
  .outcome-card:hover { background: var(--navy-mid); }
  .outcome-num { font-family: "Cormorant Garamond", serif; font-size: 80px; font-weight: 300; line-height: 1; position: absolute; top: -8px; right: 28px; background: linear-gradient(135deg, rgba(196,151,59,0.2) 0%, transparent 65%); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; pointer-events: none; }
  .outcome-tag { font-size: 10px; letter-spacing: 0.22em; text-transform: uppercase; color: var(--gold); font-weight: 700; margin-bottom: 16px; }
  .outcome-title { font-family: "Cormorant Garamond", serif; font-size: 34px; font-weight: 300; color: var(--warm-white); margin-bottom: 20px; line-height: 1.1; }
  .outcome-title em { font-style: italic; color: var(--gold-light); }
  .outcome-desc { font-size: 15px; line-height: 1.75; color: var(--muted-light); font-weight: 300; margin-bottom: 28px; }
  .outcome-list { list-style: none; padding: 0; border-top: 1px solid var(--border); padding-top: 24px; }
  .outcome-list li { display: flex; align-items: flex-start; gap: 10px; padding: 8px 0; font-size: 13px; color: var(--muted-light); font-weight: 300; line-height: 1.5; }
  .outcome-list li::before { content: "→"; color: var(--gold); flex-shrink: 0; font-size: 12px; margin-top: 1px; }
  .equation { margin-top: 64px; padding: 48px 52px; border: 1px solid var(--border); background: var(--navy-mid); display: flex; align-items: center; gap: 0; }
  .eq-item { flex: 1; padding: 0 32px; text-align: center; }
  .eq-item:not(:last-child) { border-right: 1px solid var(--border); }
  .eq-number { font-family: "Cormorant Garamond", serif; font-size: 48px; font-weight: 300; color: var(--gold-light); line-height: 1; margin-bottom: 8px; }
  .eq-label { font-family: "Cormorant Garamond", serif; font-size: 17px; color: var(--cream); margin-bottom: 8px; font-weight: 400; }
  .eq-desc { font-size: 13px; color: var(--muted); line-height: 1.5; font-weight: 300; }

  /* TWO PILLARS */
  .pillars { background: var(--navy-mid); }
  .pillars-header { display: grid; grid-template-columns: 1fr 1fr; gap: 80px; align-items: end; margin-bottom: 64px; }
  .pillars-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 2px; background: var(--border); }
  .pillar-card { background: var(--navy-mid); padding: 48px 36px; position: relative; overflow: hidden; transition: background 0.3s; }
  .pillar-card:hover { background: #192c42; }
  .pillar-num { font-family: "Cormorant Garamond", serif; font-size: 96px; font-weight: 300; line-height: 1; margin-bottom: 0; position: absolute; top: -10px; right: 32px; color: var(--gold-pale); background: linear-gradient(135deg, rgba(196,151,59,0.25) 0%, transparent 70%); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; pointer-events: none; }
  .pillar-tag { font-size: 10px; letter-spacing: 0.2em; text-transform: uppercase; color: var(--gold); font-weight: 700; margin-bottom: 20px; }
  .pillar-title { font-family: "Cormorant Garamond", serif; font-size: 38px; font-weight: 300; color: var(--warm-white); margin-bottom: 20px; line-height: 1.15; }
  .pillar-title em { font-style: italic; color: var(--gold-light); }
  .pillar-desc { font-size: 15px; line-height: 1.75; color: var(--muted-light); font-weight: 300; margin-bottom: 36px; }

  /* PILLAR COLLAPSE TOGGLE */
  .pillar-toggle { display: flex; align-items: center; justify-content: space-between; gap: 10px; background: none; border: none; border-top: 1px solid var(--border); color: var(--gold); font-family: Karla, system-ui, sans-serif; font-size: 11px; letter-spacing: 0.12em; text-transform: uppercase; font-weight: 600; cursor: pointer; padding: 16px 0 0; width: 100%; margin-top: 20px; transition: color 0.2s; }
  .pillar-toggle:hover { color: var(--gold-light); }
  .pillar-toggle span { flex: 1; text-align: left; }

  .pillar-features { list-style: none; padding: 0; }
  .pillar-feature { display: flex; align-items: flex-start; gap: 12px; padding: 10px 0; border-bottom: 1px solid var(--border); font-size: 14px; color: var(--muted-light); font-weight: 300; }
  .pillar-feature:last-child { border-bottom: none; }
  .pillar-feature::before { content: "→"; color: var(--gold); flex-shrink: 0; font-size: 13px; margin-top: 1px; }
  .pillar-ai-badge { display: inline-flex; align-items: center; gap: 8px; margin-top: 28px; padding: 8px 16px; border: 1px solid var(--border); font-size: 11px; letter-spacing: 0.1em; text-transform: uppercase; color: var(--muted); }
  .pillar-ai-dot { width: 6px; height: 6px; border-radius: 50%; background: var(--gold); }


  /* THE HX TEAM */
  .team-callout { background: var(--navy-light); border: 1px solid var(--border); padding: 36px; margin: 32px 0 36px; }
  .team-callout-label { font-size: 10px; letter-spacing: 0.22em; text-transform: uppercase; color: var(--gold); font-weight: 700; margin-bottom: 14px; }
  .team-callout-headline { font-family: "Cormorant Garamond", serif; font-size: 26px; font-weight: 300; color: var(--cream); margin-bottom: 10px; line-height: 1.2; }
  .team-callout-sub { font-size: 14px; color: var(--muted-light); line-height: 1.65; font-weight: 300; margin-bottom: 24px; }
  .team-role-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 2px; background: var(--border); }
  .team-role-card { background: var(--navy-mid); padding: 14px 16px; display: flex; gap: 12px; align-items: flex-start; transition: background 0.2s; }
  .team-role-card:hover { background: #243d5c; }
  .team-role-title { font-size: 13px; color: var(--cream); font-weight: 500; margin-bottom: 3px; letter-spacing: 0.01em; }
  .team-role-desc { font-size: 12px; color: var(--muted); line-height: 1.5; font-weight: 300; }

  /* THE HX FRAME™ */
  .hx-frame-section { background: var(--navy); }
  .hxf-layout { display: grid; grid-template-columns: 1fr 1.2fr; gap: 80px; align-items: center; }
  .hxf-diagram { position: relative; border: 1.5px solid var(--gold); }
  .hxf-nameplate { position: absolute; top: -13px; left: 28px; background: var(--navy); padding: 2px 14px; font-family: "Cormorant Garamond", serif; font-size: 12px; letter-spacing: 0.15em; text-transform: uppercase; color: var(--gold); font-weight: 600; white-space: nowrap; }
  .hxf-edge { padding: 28px 30px; display: flex; align-items: flex-start; gap: 16px; transition: background 0.25s; }
  .hxf-edge.top { border-bottom: 1px solid var(--border); }
  .hxf-edge.bottom { border-top: 1px solid var(--border); }
  .hxf-edge:hover { background: rgba(196,151,59,0.05); }
  .hxf-field { padding: 28px 30px; background: var(--navy-mid); display: flex; align-items: flex-start; gap: 16px; transition: background 0.25s; }
  .hxf-field:hover { background: #1c3149; }
  .hxf-edge-label { font-size: 10px; letter-spacing: 0.2em; text-transform: uppercase; font-weight: 700; margin-bottom: 6px; }
  .hxf-edge .hxf-edge-label { color: var(--gold); }
  .hxf-field .hxf-edge-label { color: #3fb87a; }
  .hxf-edge-title { font-family: "Cormorant Garamond", serif; font-size: 20px; color: var(--cream); margin-bottom: 8px; line-height: 1.2; }
  .hxf-edge-desc { font-size: 13px; color: var(--muted-light); line-height: 1.65; font-weight: 300; }
  .hxf-payoff { margin-top: 40px; padding-top: 32px; border-top: 1px solid var(--border); }
  .hxf-payoff-label { font-size: 10px; letter-spacing: 0.22em; text-transform: uppercase; color: var(--gold); font-weight: 700; margin-bottom: 12px; }
  .hxf-payoff-text { font-family: "Cormorant Garamond", serif; font-size: 26px; font-weight: 300; color: var(--cream); line-height: 1.35; }
  .hxf-payoff-text em { font-style: italic; color: var(--gold-light); }

  /* JOURNEY / USE CASE */
  .journey { background: var(--navy-light); }
  .journey-intro { display: grid; grid-template-columns: 1.2fr 1fr; gap: 80px; align-items: end; margin-bottom: 72px; }
  .journey-stages { display: grid; grid-template-columns: repeat(3, 1fr); gap: 2px; background: var(--border); margin-bottom: 48px; }
  .stage-tab { background: var(--navy-light); padding: 28px 32px; cursor: pointer; transition: background 0.25s, border-color 0.25s; border-top: 3px solid transparent; }
  .stage-tab:hover { background: #263d5a; }
  .stage-tab.active-auto { background: rgba(42,107,82,0.12); border-top-color: #3fb87a; }
  .stage-tab.active-human { background: var(--human-light); border-top-color: var(--human); }
  .stage-tab-badge { display: inline-flex; align-items: center; gap: 6px; font-size: 10px; letter-spacing: 0.15em; text-transform: uppercase; font-weight: 700; margin-bottom: 12px; padding: 4px 10px; }
  .badge-auto { background: rgba(63,184,122,0.15); color: #3fb87a; border: 1px solid rgba(63,184,122,0.3); }
  .badge-human { background: var(--human-light); color: #6dafd4; border: 1px solid rgba(58,124,165,0.3); }
  .stage-tab-title { font-family: "Cormorant Garamond", serif; font-size: 22px; color: var(--cream); margin-bottom: 8px; line-height: 1.2; }
  .stage-tab-sub { font-size: 13px; color: var(--muted-light); font-weight: 300; line-height: 1.5; }
  .journey-panel { display: grid; grid-template-columns: 1fr 1fr; gap: 2px; background: var(--border); }
  .chat-window { background: var(--navy-mid); padding: 0; overflow: hidden; }
  .chat-header { background: var(--navy); padding: 20px 28px; border-bottom: 1px solid var(--border); display: flex; align-items: center; gap: 12px; }
  .chat-header-dot { width: 8px; height: 8px; border-radius: 50%; }
  .dot-auto { background: #3fb87a; }
  .dot-human { background: var(--human); }
  .chat-header-title { font-size: 13px; color: var(--cream); font-weight: 500; }
  .chat-header-sub { font-size: 11px; color: var(--muted); margin-left: auto; }
  .chat-messages { padding: 24px; display: flex; flex-direction: column; gap: 16px; min-height: 320px; }
  .msg { display: flex; gap: 10px; }
  .msg-avatar { width: 28px; height: 28px; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 11px; flex-shrink: 0; margin-top: 2px; }
  .avatar-user { background: var(--navy-light); color: var(--muted-light); font-weight: 600; }
  .avatar-agent { background: rgba(63,184,122,0.2); color: #3fb87a; font-weight: 600; }
  .avatar-hr { background: var(--human-light); color: #6dafd4; font-weight: 600; }
  .msg-bubble { max-width: 85%; padding: 12px 16px; border-radius: 0; font-size: 14px; line-height: 1.6; font-weight: 300; }
  .bubble-user { background: var(--navy); color: var(--cream); border: 1px solid var(--border); margin-left: auto; }
  .bubble-agent { background: rgba(63,184,122,0.08); color: var(--cream); border: 1px solid rgba(63,184,122,0.2); }
  .bubble-hr { background: var(--human-light); color: var(--cream); border: 1px solid rgba(58,124,165,0.3); }
  .msg-sender { font-size: 10px; color: var(--muted); text-transform: uppercase; letter-spacing: 0.1em; margin-bottom: 4px; font-weight: 600; }
  .msg-user { flex-direction: row-reverse; }
  .insight-panel { background: var(--navy); padding: 40px 36px; display: flex; flex-direction: column; justify-content: space-between; }
  .insight-eyebrow { font-size: 10px; letter-spacing: 0.2em; text-transform: uppercase; color: var(--gold); font-weight: 700; margin-bottom: 20px; }
  .insight-title { font-family: "Cormorant Garamond", serif; font-size: 28px; font-weight: 300; color: var(--warm-white); line-height: 1.2; margin-bottom: 20px; }
  .insight-text { font-size: 15px; line-height: 1.75; color: var(--muted-light); font-weight: 300; }
  .insight-principle { margin-top: 32px; padding-top: 28px; border-top: 1px solid var(--border); }
  .principle-label { font-size: 10px; letter-spacing: 0.15em; text-transform: uppercase; color: var(--gold); font-weight: 700; margin-bottom: 10px; }
  .principle-text { font-family: "Cormorant Garamond", serif; font-size: 20px; font-style: italic; color: var(--cream); line-height: 1.4; }

  /* HOW IT WORKS */
  .how { background: var(--navy-mid); position: relative; }
  .process-steps { display: grid; grid-template-columns: repeat(4, 1fr); gap: 0; margin-top: 64px; position: relative; }
  .process-steps::before { content: ""; position: absolute; top: 48px; left: 12%; right: 12%; height: 1px; background: linear-gradient(90deg, transparent, var(--gold), var(--gold), transparent); z-index: 0; }
  .process-step { padding: 0 24px; text-align: center; position: relative; z-index: 1; }
  .step-circle { width: 96px; height: 96px; border-radius: 50%; border: 1px solid var(--border); background: var(--navy-mid); display: flex; flex-direction: column; align-items: center; justify-content: center; margin: 0 auto 28px; transition: border-color 0.3s, background 0.3s; }
  .process-step:hover .step-circle { border-color: var(--gold); background: var(--gold-pale); }
  .step-num { font-family: "Cormorant Garamond", serif; font-size: 13px; color: var(--gold); letter-spacing: 0.1em; }
  .step-icon { font-size: 22px; margin-top: 2px; }
  .step-title { font-family: "Cormorant Garamond", serif; font-size: 24px; font-weight: 400; color: var(--cream); margin-bottom: 12px; }
  .step-text { font-size: 14px; line-height: 1.6; color: var(--muted-light); font-weight: 300; }

  /* RESULTS */
  .results-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 2px; background: rgba(196,151,59,0.15); margin-top: 64px; }
  .result-item { background: var(--navy-light); padding: 44px 36px; transition: background 0.3s; cursor: default; }
  .result-item:hover { background: #243d5c; }
  .result-number { font-family: "Cormorant Garamond", serif; font-size: 52px; font-weight: 300; color: var(--gold-light); line-height: 1; margin-bottom: 8px; }
  .result-label { font-family: "Cormorant Garamond", serif; font-size: 18px; color: var(--cream); margin-bottom: 14px; font-weight: 400; }
  .result-context { font-size: 13px; line-height: 1.6; color: var(--muted-light); font-weight: 300; }

  /* ABOUT */
  .about { background: var(--navy); }
  .about-layout { display: grid; grid-template-columns: 1fr 1.4fr; gap: 80px; align-items: center; }
  .about-portrait { aspect-ratio: 3/4; background: var(--navy-light); border: 1px solid var(--border); position: relative; overflow: hidden; display: flex; align-items: center; justify-content: center; }
  .about-portrait img { width: 100%; height: 100%; object-fit: cover; object-position: center top; }
  .about-portrait::after { content: ""; position: absolute; bottom: 0; left: 0; right: 0; height: 35%; background: linear-gradient(to top, var(--navy), transparent); }
  .about-portrait-tag { position: absolute; bottom: 20px; left: 20px; z-index: 1; background: var(--gold); color: var(--navy); padding: 8px 16px; font-size: 11px; letter-spacing: 0.1em; text-transform: uppercase; font-weight: 700; }
  .about-name { font-family: "Cormorant Garamond", serif; font-size: 48px; font-weight: 300; color: var(--warm-white); margin-bottom: 4px; line-height: 1; }
  .about-title { font-size: 13px; letter-spacing: 0.15em; text-transform: uppercase; color: var(--gold); margin-bottom: 28px; font-weight: 600; }
  .about-bio { font-size: 16px; line-height: 1.8; color: var(--muted-light); font-weight: 300; margin-bottom: 32px; }
  .about-bio strong { color: var(--cream); font-weight: 500; }
  .about-creds { display: flex; flex-wrap: wrap; gap: 10px; margin-bottom: 32px; }
  .cred-tag { border: 1px solid var(--border); padding: 6px 14px; font-size: 11px; letter-spacing: 0.08em; text-transform: uppercase; color: var(--muted-light); font-weight: 500; }
  .podcast-callout { background: var(--gold-pale); border: 1px solid var(--border); padding: 20px 24px; display: flex; align-items: center; gap: 16px; }
  .podcast-icon { font-size: 28px; }
  .podcast-label { font-size: 11px; letter-spacing: 0.1em; text-transform: uppercase; color: var(--gold); font-weight: 600; margin-bottom: 4px; }
  .podcast-name { font-family: "Cormorant Garamond", serif; font-size: 20px; color: var(--cream); }

  /* WHY HX */
  .why { background: var(--navy-mid); }
  .why-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 2px; background: var(--border); margin-top: 64px; }
  .why-card { background: var(--navy-mid); padding: 48px 36px; transition: background 0.3s; }
  .why-card:hover { background: var(--navy-light); }
  .why-card-icon { font-size: 32px; margin-bottom: 24px; display: block; }
  .why-card-title { font-family: "Cormorant Garamond", serif; font-size: 24px; color: var(--cream); margin-bottom: 16px; font-weight: 400; }
  .why-card-text { font-size: 15px; line-height: 1.7; color: var(--muted-light); font-weight: 300; }
  .why-card-feature { margin-top: 24px; padding-top: 24px; border-top: 1px solid var(--border); font-size: 12px; letter-spacing: 0.08em; text-transform: uppercase; color: var(--gold); font-weight: 600; }

  /* FOOTER CTA */
  .footer-cta { background: var(--navy-light); padding: 120px 60px; text-align: center; position: relative; overflow: hidden; }
  .footer-cta::before { content: ""; position: absolute; inset: 0; background: radial-gradient(ellipse 60% 80% at 50% 50%, rgba(196,151,59,0.08) 0%, transparent 70%); }
  .footer-cta-content { position: relative; }
  .footer-cta-eyebrow { font-size: 11px; letter-spacing: 0.2em; text-transform: uppercase; color: var(--gold); margin-bottom: 24px; font-weight: 600; }
  .footer-cta-title { font-family: "Cormorant Garamond", serif; font-size: clamp(40px, 5vw, 64px); font-weight: 300; color: var(--warm-white); margin-bottom: 20px; line-height: 1.1; }
  .footer-cta-title em { font-style: italic; color: var(--gold-light); }
  .footer-cta-sub { font-size: 17px; color: var(--muted-light); font-weight: 300; max-width: 480px; margin: 0 auto 48px; line-height: 1.7; }
  .footer-cta-btns { display: flex; gap: 16px; justify-content: center; flex-wrap: wrap; }

  /* FOOTER */
  .footer { background: var(--navy); padding: 48px 60px; display: flex; align-items: center; justify-content: space-between; border-top: 1px solid var(--border); }
  .footer-logo { font-family: "Cormorant Garamond", serif; font-size: 20px; color: var(--cream); }
  .footer-logo span { color: var(--gold); }
  .footer-links { display: flex; gap: 28px; list-style: none; font-size: 12px; letter-spacing: 0.08em; text-transform: uppercase; }
  .footer-links a { color: var(--muted); text-decoration: none; transition: color 0.2s; }
  .footer-links a:hover { color: var(--gold); }
  .footer-copy { font-size: 12px; color: var(--muted); }



  /* INFRASTRUCTURE */
  .infra { background: var(--navy); }
  .infra-layout { display: grid; grid-template-columns: 1fr 1.1fr; gap: 80px; align-items: start; }
  .infra-stack { display: flex; flex-direction: column; gap: 2px; }
  .infra-card { background: var(--navy-mid); padding: 28px 32px; border-left: 3px solid transparent; transition: border-color 0.3s, background 0.3s; }
  .infra-card:hover { background: var(--navy-light); border-left-color: var(--gold); }
  .infra-card-header { display: flex; align-items: flex-start; gap: 14px; margin-bottom: 12px; }
  .infra-card-label { font-size: 10px; letter-spacing: 0.2em; text-transform: uppercase; color: var(--gold); font-weight: 700; margin-bottom: 4px; }
  .infra-card-title { font-family: "Cormorant Garamond", serif; font-size: 20px; color: var(--cream); font-weight: 400; line-height: 1.2; }
  .infra-card-text { font-size: 14px; line-height: 1.7; color: var(--muted-light); font-weight: 300; }
  .infra-tools { display: flex; gap: 8px; flex-wrap: wrap; margin-top: 16px; }
  .tool-badge { border: 1px solid var(--border); padding: 4px 12px; font-size: 10px; color: var(--muted-light); letter-spacing: 0.1em; text-transform: uppercase; font-weight: 500; }
  .tool-badge.primary { border-color: var(--gold); color: var(--gold); font-weight: 700; }
  .infra-sub-note { margin-top: 40px; padding-top: 32px; border-top: 1px solid var(--border); }
  .infra-sub-note-label { font-size: 10px; letter-spacing: 0.2em; text-transform: uppercase; color: var(--gold); font-weight: 700; margin-bottom: 10px; }
  .infra-sub-note-text { font-family: "Cormorant Garamond", serif; font-size: 20px; font-style: italic; color: var(--cream); line-height: 1.45; font-weight: 300; }

  /* BRAND ICONS */
  .icon-block { margin-bottom: 24px; }
  .pillar-icon-block { margin-bottom: 22px; }
  .outcome-icon-block { margin-bottom: 18px; }
  .step-icon-svg { display: flex; align-items: center; justify-content: center; margin-top: 4px; }
  .why-icon-block { margin-bottom: 22px; }
  .about-hx-mark { display: flex; align-items: center; gap: 14px; margin-bottom: 6px; }

  /* ANIMATIONS */
  @keyframes fadeUp { from { opacity: 0; transform: translateY(24px); } to { opacity: 1; transform: translateY(0); } }
  .animate-in { animation: fadeUp 0.8s ease forwards; }
  .delay-1 { animation-delay: 0.15s; opacity: 0; }
  .delay-2 { animation-delay: 0.3s; opacity: 0; }
  .delay-3 { animation-delay: 0.45s; opacity: 0; }
  .delay-4 { animation-delay: 0.6s; opacity: 0; }

  /* MOBILE */
  @media (max-width: 960px) {
    .nav { padding: 20px 24px; }
    .nav-links { display: none; }
    section { padding: 80px 24px; }
    .hero { grid-template-columns: 1fr; min-height: auto; }
    .hero-left { padding: 120px 24px 60px; }
    .hero-right { height: 380px; padding-top: 0; }
    .hero-right .hero-photo { object-position: 50% 20%; }
    .hero-stats { flex-wrap: wrap; gap: 24px; }
    .philosophy-inner { grid-template-columns: 1fr; }
    .pillars-header { grid-template-columns: 1fr; gap: 24px; }
    .pillars-grid { grid-template-columns: 1fr; }
    .hxf-layout { grid-template-columns: 1fr; gap: 48px; }
    .journey-intro { grid-template-columns: 1fr; gap: 24px; }
    .journey-stages { grid-template-columns: 1fr; }
    .journey-panel { grid-template-columns: 1fr; }
    .infra-layout { grid-template-columns: 1fr; gap: 48px; }
    .outcomes-grid { grid-template-columns: 1fr; }
    .team-role-grid { grid-template-columns: 1fr; }
    .equation { flex-direction: column; gap: 24px; }
    .eq-item { border-right: none !important; border-bottom: 1px solid var(--border); padding-bottom: 24px; }
    .process-steps { grid-template-columns: 1fr 1fr; gap: 32px; }
    .process-steps::before { display: none; }
    .results-grid { grid-template-columns: 1fr 1fr; }
    .why-grid { grid-template-columns: 1fr; }
    .about-layout { grid-template-columns: 1fr; gap: 48px; }
    .about-portrait { aspect-ratio: 4/3; max-height: 320px; }
    .footer { flex-direction: column; gap: 24px; text-align: center; }
    .footer-links { flex-wrap: wrap; justify-content: center; }
    .footer-cta { padding: 80px 24px; }
  }
`;

